"""
PR: Add API key authentication middleware
"""
import hashlib
from flask import request, jsonify, g
from app.models import ApiKey

def require_api_key(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        api_key = request.headers.get('X-API-Key')
        if not api_key:
            return jsonify({'error': 'Missing API key'}), 401
        key_hash = hashlib.sha256(api_key.encode()).hexdigest()
        key_record = ApiKey.query.filter_by(key_hash=key_hash).first()
        if not key_record:
            return jsonify({'error': 'Invalid API key'}), 403
        if not key_record.is_active:
            return jsonify({'error': 'API key is deactivated'}), 403
        g.organization_id = key_record.organization_id
        g.api_key_id = key_record.id
        return f(*args, **kwargs)
    return decorated_function

@data_bp.route('/orders', methods=['GET'])
@require_api_key
def list_orders():
    orders = Order.query.filter_by(organization_id=g.organization_id).all()
    return jsonify({'orders': [o.to_dict() for o in orders]})

@data_bp.route('/orders/<int:order_id>', methods=['GET'])
@require_api_key
def get_order(order_id):
    order = Order.query.get(order_id)
    if not order:
        return jsonify({'error': 'Order not found'}), 404
    return jsonify(order.to_dict())

# Tests:
def test_missing_api_key_returns_401(client):
    response = client.get('/api/orders')
    assert response.status_code == 401

def test_invalid_api_key_returns_403(client):
    response = client.get('/api/orders', headers={'X-API-Key': 'invalid-key-12345'})
    assert response.status_code == 403
